import{_ as r,C as o,o as n,c as l,j as s,a,E as i,ai as d}from"./chunks/framework.-fuqNImP.js";const k=JSON.parse('{"title":"Build Skills","description":"","frontmatter":{},"headers":[],"relativePath":"courses/build-skills.md","filePath":"courses/build-skills.md"}'),c={name:"courses/build-skills.md"};function h(u,e,p,m,g,b){const t=o("Badge");return n(),l("div",null,[e[0]||(e[0]=s("h1",{id:"build-skills",tabindex:"-1"},[a("Build Skills "),s("a",{class:"header-anchor",href:"#build-skills","aria-label":'Permalink to "Build Skills"'},"​")],-1)),i(t,{type:"warning",text:"Intermediate"}),e[1]||(e[1]=a()),i(t,{type:"info",text:"11 Modules"}),e[2]||(e[2]=a()),i(t,{type:"tip",text:"Partial Narration"}),e[3]||(e[3]=d('<p>Page objects, API testing, auth fixtures, test data, and CI/CD integration. This course bridges the gap between writing tests and building a sustainable test practice.</p><h2 id="course-overview" tabindex="-1">Course Overview <a class="header-anchor" href="#course-overview" aria-label="Permalink to &quot;Course Overview&quot;">​</a></h2><p>Build Skills draws from the legacy curriculum (modules 11–21) to cover intermediate topics that every test automation engineer needs. Topics include prompt engineering, CI/CD, authentication patterns, and accessibility testing.</p><div class="info custom-block"><p class="custom-block-title">Content Status</p><p>All 11 modules are authored with quizzes and exercises. Some modules are still awaiting narration scripts.</p></div><h2 id="module-breakdown" tabindex="-1">Module Breakdown <a class="header-anchor" href="#module-breakdown" aria-label="Permalink to &quot;Module Breakdown&quot;">​</a></h2><h3 id="_11-prompt-templates" tabindex="-1">11. Prompt Templates <a class="header-anchor" href="#_11-prompt-templates" aria-label="Permalink to &quot;11. Prompt Templates&quot;">​</a></h3><p>Reusable prompt patterns for Copilot. Structure templates with context, task, and constraints for consistent test generation.</p><h3 id="_12-reading-results" tabindex="-1">12. Reading Results <a class="header-anchor" href="#_12-reading-results" aria-label="Permalink to &quot;12. Reading Results&quot;">​</a></h3><p>Deep dive into Playwright&#39;s output formats — terminal, HTML report, trace files, JUnit XML. Interpret failures like evidence.</p><h3 id="_13-human-in-the-loop-checklist" tabindex="-1">13. Human-in-the-Loop Checklist <a class="header-anchor" href="#_13-human-in-the-loop-checklist" aria-label="Permalink to &quot;13. Human-in-the-Loop Checklist&quot;">​</a></h3><p>Quality gates for automated tests. When to trust automation, when to manually verify, and how to blend both approaches.</p><h3 id="_14-collaborative-test-authoring" tabindex="-1">14. Collaborative Test Authoring <a class="header-anchor" href="#_14-collaborative-test-authoring" aria-label="Permalink to &quot;14. Collaborative Test Authoring&quot;">​</a></h3><p>Working with developers on test code. PR review patterns, shared page objects, and test ownership models.</p><h3 id="_15-ci-cd-reference" tabindex="-1">15. CI/CD Reference <a class="header-anchor" href="#_15-ci-cd-reference" aria-label="Permalink to &quot;15. CI/CD Reference&quot;">​</a></h3><p>Running Playwright in GitHub Actions. Configuration, artifacts, retries, and parallel execution in pipelines.</p><h3 id="_16-auth-fixtures" tabindex="-1">16. Auth Fixtures <a class="header-anchor" href="#_16-auth-fixtures" aria-label="Permalink to &quot;16. Auth Fixtures&quot;">​</a></h3><p>Reusable authentication state with Playwright fixtures. <code>storageState</code>, global setup, and role-based test contexts.</p><h3 id="_17-visual-regression" tabindex="-1">17. Visual Regression <a class="header-anchor" href="#_17-visual-regression" aria-label="Permalink to &quot;17. Visual Regression&quot;">​</a></h3><p>Screenshot comparison testing. Baseline management, threshold configuration, and handling expected visual changes.</p><h3 id="_18-accessibility-testing" tabindex="-1">18. Accessibility Testing <a class="header-anchor" href="#_18-accessibility-testing" aria-label="Permalink to &quot;18. Accessibility Testing&quot;">​</a></h3><p>Automated a11y checks with <code>@axe-core/playwright</code>. WCAG compliance, custom rules, and the practice app&#39;s intentional violations.</p><h3 id="_19-flaky-test-diagnosis" tabindex="-1">19. Flaky Test Diagnosis <a class="header-anchor" href="#_19-flaky-test-diagnosis" aria-label="Permalink to &quot;19. Flaky Test Diagnosis&quot;">​</a></h3><p>Root causes of test flakiness — timing, shared state, network dependencies. Systematic debugging with <code>--repeat-each</code> and traces.</p><h3 id="_20-test-data-strategies" tabindex="-1">20. Test Data Strategies <a class="header-anchor" href="#_20-test-data-strategies" aria-label="Permalink to &quot;20. Test Data Strategies&quot;">​</a></h3><p>Managing test data — factories, fixtures, API seeding, and cleanup. Avoiding test coupling through data isolation.</p><h2 id="skills-matrix" tabindex="-1">Skills Matrix <a class="header-anchor" href="#skills-matrix" aria-label="Permalink to &quot;Skills Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Category</th><th>Difficulty</th></tr></thead><tbody><tr><td>11–13</td><td>Review &amp; Process</td><td>⭐⭐</td></tr><tr><td>14–15</td><td>Team &amp; CI/CD</td><td>⭐⭐</td></tr><tr><td>16–18</td><td>Testing Patterns</td><td>⭐⭐⭐</td></tr><tr><td>19–20</td><td>Reliability</td><td>⭐⭐⭐</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/midnight-automation-voyage/courses/go-pro">Go Pro</a> — advanced topics for scaling test automation</li><li><a href="/midnight-automation-voyage/reference/architecture">Architecture Reference</a> — understand the platform design decisions</li></ul>',29))])}const x=r(c,[["render",h]]);export{k as __pageData,x as default};
